const parser = {
  name: "svelte-eslint-parser",
  parseForESLint(code) {
    const errorIndex = code.indexOf("}");
    const error = new SyntaxError("Unexpected token");
    error.index = errorIndex;
    error.lineNumber = 1;
    error.column = errorIndex;
    throw error;
  },
};

const plugin = {
  meta: {
    name: "svelte",
  },
  rules: {
    "parse-canary": {
      create() {
        return {};
      },
    },
  },
  configs: {
    recommended: {
      jsPlugins: ["eslint-plugin-svelte"],
      overrides: [
        {
          files: ["**/*.svelte"],
          languageOptions: {
            parser,
          },
          rules: {
            "svelte/parse-canary": "error",
          },
        },
      ],
    },
  },
};

export default plugin;
